CREATE TABLE IF NOT EXISTS t_p61016064_digital_innovation_i.wb_initiatives (id SERIAL PRIMARY KEY, case_id INTEGER, user_id INTEGER NOT NULL, title TEXT NOT NULL, description TEXT, owner_name TEXT, sponsor TEXT, priority TEXT NOT NULL DEFAULT 'medium', impact_score INTEGER NOT NULL DEFAULT 3, effort_score INTEGER NOT NULL DEFAULT 3, data_readiness TEXT NOT NULL DEFAULT 'low', tech_readiness TEXT NOT NULL DEFAULT 'low', regulatory_risk TEXT NOT NULL DEFAULT 'medium', ai_readiness TEXT NOT NULL DEFAULT 'low', target_start_date DATE, target_end_date DATE, status TEXT NOT NULL DEFAULT 'idea', next_step TEXT, is_archived BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE INDEX IF NOT EXISTS idx_wb_init_user ON t_p61016064_digital_innovation_i.wb_initiatives(user_id); CREATE INDEX IF NOT EXISTS idx_wb_init_status ON t_p61016064_digital_innovation_i.wb_initiatives(status);